#pragma once

#include <cuda.h>
#include <cuda_runtime.h>
#include <torch/extension.h>
#include <vector>

// Constants defined by the specification
constexpr int NUM_QO_HEADS = 16;
constexpr int HEAD_DIM_CKV = 512;
constexpr int HEAD_DIM_KPE = 64;
constexpr int PAGE_SIZE = 64;
constexpr int TOPK = 2048;
constexpr int TOPK_TILE = 64;
constexpr int BLOCK_THREADS = 256;

// Kernel Launch Helper
void launch_sparse_attention_kernel(
    const void* q_nope,
    const void* q_pe,
    const void* ckv_cache,
    const void* kpe_cache,
    const int* sparse_indices,
    void* output,
    float* lse,
    float sm_scale,
    int num_tokens
);

// Host Function Declaration
std::vector<at::Tensor> run(
    const at::Tensor& q_nope,
    const at::Tensor& q_pe,
    const at::Tensor& ckv_cache,
    const at::Tensor& kpe_cache,
    const at::Tensor& sparse_indices,
    float sm_scale
);

#include <cuda.h>
#include <cuda_runtime.h>
#include <cuda_fp16.h>
#include <cuda_bf16.h>
#include <math_constants.h>
#include <torch/extension.h>
#include "kernel.h"

#define CUDA_KERNEL_LOOP(i, n) \
    for (int i = blockIdx.x * blockDim.x + threadIdx.x; i < (n); i += blockDim.x * gridDim.x)

// Helper for bfloat16 conversion
__device__ inline float __bfloat16_to_float(__nv_bfloat16 val) {
    return __bfloat162float(val);
}

__device__ inline __nv_bfloat16 __float_to_bfloat16(float val) {
    return __float2bfloat16(val);
}

__global__ void sparse_attention_kernel(
    const __nv_bfloat16* __restrict__ q_nope,
    const __nv_bfloat16* __restrict__ q_pe,
    const __nv_bfloat16* __restrict__ ckv_cache,
    const __nv_bfloat16* __restrict__ kpe_cache,
    const int* __restrict__ sparse_indices,
    __nv_bfloat16* __restrict__ output,
    float* __restrict__ lse,
    float sm_scale,
    int num_tokens
) {
    // One block per token
    int token_idx = blockIdx.x;
    if (token_idx >= num_tokens) return;

    // Thread ID and Block Info
    int tid = threadIdx.x;
    int num_threads = blockDim.x;

    // Shared Memory for Q and Q_pe (load once per token)
    __shared__ __nv_bfloat16 Q[NUM_QO_HEADS][HEAD_DIM_CKV];
    __shared__ __nv_bfloat16 Q_pe[NUM_QO_HEADS][HEAD_DIM_KPE];

    // Shared Memory for K tiles (reused across tiles)
    __shared__ __nv_bfloat16 K_V_tile[TOPK_TILE][HEAD_DIM_CKV];
    __shared__ __nv_bfloat16 Kpe_tile[TOPK_TILE][HEAD_DIM_KPE];

    // Shared Memory for logits per tile
    __shared__ float S_tile[NUM_QO_HEADS][TOPK_TILE];

    // Per-thread output accumulation buffer
    __shared__ float output_acc[NUM_QO_HEADS][HEAD_DIM_CKV];

    // 1. Load Q into Shared Memory
    int q_elements = NUM_QO_HEADS * HEAD_DIM_CKV;
    int q_start = tid * (q_elements / num_threads);
    int q_end = (tid + 1) * (q_elements / num_threads);
    if (tid == num_threads - 1) q_end = q_elements;

    const __nv_bfloat16* q_ptr = q_nope + token_idx * q_elements;
    for (int i = q_start; i < q_end; ++i) {
        int head = i / HEAD_DIM_CKV;
        int dim = i % HEAD_DIM_CKV;
        Q[head][dim] = q_ptr[i];
    }
    __syncthreads();

    // 2. Load Q_pe into Shared Memory
    int qpe_elements = NUM_QO_HEADS * HEAD_DIM_KPE;
    int qpe_start = tid * (qpe_elements / num_threads);
    int qpe_end = (tid + 1) * (qpe_elements / num_threads);
    if (tid == num_threads - 1) qpe_end = qpe_elements;

    const __nv_bfloat16* qpe_ptr = q_pe + token_idx * qpe_elements;
    for (int i = qpe_start; i < qpe_end; ++i) {
        int head = i / HEAD_DIM_KPE;
        int dim = i % HEAD_DIM_KPE;
        Q_pe[head][dim] = qpe_ptr[i];
    }
    __syncthreads();

    // 3. Initialize running LSE (max and sum) for each head
    float head_max[NUM_QO_HEADS];
    float head_sum[NUM_QO_HEADS];
    for (int h = 0; h < NUM_QO_HEADS; ++h) {
        head_max[h] = -INFINITY;
        head_sum[h] = 0.0f;
    }

    // 4. Initialize output accumulation
    for (int i = tid; i < NUM_QO_HEADS * HEAD_DIM_CKV; i += num_threads) {
        int head = i / HEAD_DIM_CKV;
        int dim = i % HEAD_DIM_CKV;
        output_acc[head][dim] = 0.0f;
    }
    __syncthreads();

    // 5. Process tiles of topk keys
    for (int tile = 0; tile < TOPK; tile += TOPK_TILE) {
        // Load Sparse Indices for this tile
        const int* indices_ptr = sparse_indices + token_idx * TOPK + tile;

        // Load K_V_tile
        int tile_elements = TOPK_TILE * HEAD_DIM_CKV;
        int tile_start = tid * (tile_elements / num_threads);
        int tile_end = (tid + 1) * (tile_elements / num_threads);
        if (tid == num_threads - 1) tile_end = tile_elements;

        for (int i = tile_start; i < tile_end; ++i) {
            int key_idx = i / HEAD_DIM_CKV;
            int dim = i % HEAD_DIM_CKV;
            int sparse_idx = indices_ptr[key_idx];

            if (sparse_idx != -1) {
                int cache_offset = sparse_idx * HEAD_DIM_CKV + dim;
                K_V_tile[key_idx][dim] = ckv_cache[cache_offset];
            } else {
                K_V_tile[key_idx][dim] = __float_to_bfloat16(0.0f);
            }
        }

        // Load Kpe_tile
        int tile_elements_kpe = TOPK_TILE * HEAD_DIM_KPE;
        int tile_start_kpe = tid * (tile_elements_kpe / num_threads);
        int tile_end_kpe = (tid + 1) * (tile_elements_kpe / num_threads);
        if (tid == num_threads - 1) tile_end_kpe = tile_elements_kpe;

        for (int i = tile_start_kpe; i < tile_end_kpe; ++i) {
            int key_idx = i / HEAD_DIM_KPE;
            int dim = i % HEAD_DIM_KPE;
            int sparse_idx = indices_ptr[key_idx];

            if (sparse_idx != -1) {
                int cache_offset = sparse_idx * HEAD_DIM_KPE + dim;
                Kpe_tile[key_idx][dim] = kpe_cache[cache_offset];
            } else {
                Kpe_tile[key_idx][dim] = __float_to_bfloat16(0.0f);
            }
        }
        __syncthreads();

        // Compute Logits for this tile
        int my_key_start = tid * (TOPK_TILE / num_threads);
        int my_key_end = (tid + 1) * (TOPK_TILE / num_threads);
        if (tid == num_threads - 1) my_key_end = TOPK_TILE;

        for (int k = my_key_start; k < my_key_end; ++k) {
            int sparse_idx = indices_ptr[k];
            if (sparse_idx == -1) {
                for (int h = 0; h < NUM_QO_HEADS; ++h) {
                    S_tile[h][k] = -INFINITY;
                }
                continue;
            }

            for (int h = 0; h < NUM_QO_HEADS; ++h) {
                float sum_ckv = 0.0f;
                float sum_kpe = 0.0f;

                // Compute dot product for CKV (unrolled by 4)
                for (int d = 0; d < HEAD_DIM_CKV; d += 4) {
                    float q0 = __bfloat16_to_float(Q[h][d]);
                    float q1 = __bfloat16_to_float(Q[h][d+1]);
                    float q2 = __bfloat16_to_float(Q[h][d+2]);
                    float q3 = __bfloat16_to_float(Q[h][d+3]);
                    float k0 = __bfloat16_to_float(K_V_tile[k][d]);
                    float k1 = __bfloat16_to_float(K_V_tile[k][d+1]);
                    float k2 = __bfloat16_to_float(K_V_tile[k][d+2]);
                    float k3 = __bfloat16_to_float(K_V_tile[k][d+3]);
                    sum_ckv += q0 * k0 + q1 * k1 + q2 * k2 + q3 * k3;
                }

                // Compute dot product for KPE (unrolled by 4)
                for (int d = 0; d < HEAD_DIM_KPE; d += 4) {
                    float q0 = __bfloat16_to_float(Q_pe[h][d]);
                    float q1 = __bfloat16_to_float(Q_pe[h][d+1]);
                    float q2 = __bfloat16_to_float(Q_pe[h][d+2]);
                    float q3 = __bfloat16_to_float(Q_pe[h][d+3]);
                    float k0 = __bfloat16_to_float(Kpe_tile[k][d]);
                    float k1 = __bfloat16_to_float(Kpe_tile[k][d+1]);
                    float k2 = __bfloat16_to_float(Kpe_tile[k][d+2]);
                    float k3 = __bfloat16_to_float(Kpe_tile[k][d+3]);
                    sum_kpe += q0 * k0 + q1 * k1 + q2 * k2 + q3 * k3;
                }

                S_tile[h][k] = sum_ckv + sum_kpe;
            }
        }
        __syncthreads();

        // Update running LSE for this tile and accumulate output (corrected online softmax)
        for (int k = my_key_start; k < my_key_end; ++k) {
            int sparse_idx = indices_ptr[k];
            if (sparse_idx == -1) continue;

            for (int h = 0; h < NUM_QO_HEADS; ++h) {
                float logit = S_tile[h][k] * sm_scale;
                float old_max = head_max[h];
                float new_max = fmaxf(old_max, logit);
                float scale = expf(old_max - new_max);
                head_sum[h] = head_sum[h] * scale + expf(logit - new_max);

                // Accumulate output with proper scaling
                float weight = expf(logit - new_max);
                int dim_start = tid * (HEAD_DIM_CKV / num_threads);
                int dim_end = (tid + 1) * (HEAD_DIM_CKV / num_threads);
                if (tid == num_threads - 1) dim_end = HEAD_DIM_CKV;

                for (int d = dim_start; d < dim_end; ++d) {
                    float v = __bfloat16_to_float(K_V_tile[k][d]);
                    output_acc[h][d] = output_acc[h][d] * scale + weight * v;
                }

                head_max[h] = new_max;
            }
        }
        __syncthreads();
    }

    // 6. Normalize and write output
    int out_elements = NUM_QO_HEADS * HEAD_DIM_CKV;
    int out_start = tid * (out_elements / num_threads);
    int out_end = (tid + 1) * (out_elements / num_threads);
    if (tid == num_threads - 1) out_end = out_elements;

    __nv_bfloat16* out_ptr = output + token_idx * out_elements;

    for (int i = out_start; i < out_end; ++i) {
        int head = i / HEAD_DIM_CKV;
        int dim = i % HEAD_DIM_CKV;

        // Normalize output
        float normalized_val = 0.0f;
        if (head_sum[head] > 0.0f) {
            normalized_val = output_acc[head][dim] / head_sum[head];
        }
        out_ptr[i] = __float_to_bfloat16(normalized_val);
    }
    __syncthreads();

    // 7. Write LSE (one thread per head)
    if (tid < NUM_QO_HEADS) {
        int h = tid;
        float lse_val = 0.0f;
        if (head_sum[h] > 0.0f) {
            lse_val = logf(head_sum[h]) + head_max[h];
        } else {
            lse_val = -INFINITY;
        }
        float lse_2base = lse_val / 0.69314718056f; // log2
        lse[token_idx * NUM_QO_HEADS + h] = lse_2base;
    }
}

void launch_sparse_attention_kernel(
    const void* q_nope,
    const void* q_pe,
    const void* ckv_cache,
    const void* kpe_cache,
    const int* sparse_indices,
    void* output,
    float* lse,
    float sm_scale,
    int num_tokens
) {
    // Launch Configuration
    int threads = BLOCK_THREADS;
    int blocks = num_tokens;

    sparse_attention_kernel<<<blocks, threads>>>(
        reinterpret_cast<const __nv_bfloat16*>(q_nope),
        reinterpret_cast<const __nv_bfloat16*>(q_pe),
        reinterpret_cast<const __nv_bfloat16*>(ckv_cache),
        reinterpret_cast<const __nv_bfloat16*>(kpe_cache),
        sparse_indices,
        reinterpret_cast<__nv_bfloat16*>(output),
        lse,
        sm_scale,
        num_tokens
    );

    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        throw std::runtime_error(std::string("CUDA kernel launch failed: ") + cudaGetErrorString(err));
    }
}

#include <torch/extension.h>
#include <ATen/ATen.h>
#include "kernel.h"

std::vector<at::Tensor> run(
    const at::Tensor& q_nope,
    const at::Tensor& q_pe,
    const at::Tensor& ckv_cache,
    const at::Tensor& kpe_cache,
    const at::Tensor& sparse_indices,
    float sm_scale
) {
    // Validate Inputs
    TORCH_CHECK(q_nope.device().is_cuda(), "q_nope must be on CUDA");
    TORCH_CHECK(q_pe.device().is_cuda(), "q_pe must be on CUDA");
    TORCH_CHECK(ckv_cache.device().is_cuda(), "ckv_cache must be on CUDA");
    TORCH_CHECK(kpe_cache.device().is_cuda(), "kpe_cache must be on CUDA");
    TORCH_CHECK(sparse_indices.device().is_cuda(), "sparse_indices must be on CUDA");

    TORCH_CHECK(q_nope.dtype() == at::kBFloat16, "q_nope must be bfloat16");
    TORCH_CHECK(q_pe.dtype() == at::kBFloat16, "q_pe must be bfloat16");
    TORCH_CHECK(ckv_cache.dtype() == at::kBFloat16, "ckv_cache must be bfloat16");
    TORCH_CHECK(kpe_cache.dtype() == at::kBFloat16, "kpe_cache must be bfloat16");
    TORCH_CHECK(sparse_indices.dtype() == at::kInt, "sparse_indices must be int32");

    int num_tokens = q_nope.size(0);
    int num_qo_heads = q_nope.size(1);
    int head_dim_ckv = q_nope.size(2);
    int head_dim_kpe = q_pe.size(2);
    int page_size = ckv_cache.size(1);
    int topk = sparse_indices.size(1);

    // Check Constants
    TORCH_CHECK(num_qo_heads == 16, "num_qo_heads must be 16");
    TORCH_CHECK(head_dim_ckv == 512, "head_dim_ckv must be 512");
    TORCH_CHECK(head_dim_kpe == 64, "head_dim_kpe must be 64");
    TORCH_CHECK(page_size == 64, "page_size must be 64");
    TORCH_CHECK(topk == 2048, "topk must be 2048");

    // Check Shapes
    TORCH_CHECK(sparse_indices.size(0) == num_tokens, "sparse_indices token dim mismatch");
    TORCH_CHECK(sparse_indices.size(1) == topk, "sparse_indices topk dim mismatch");
    TORCH_CHECK(ckv_cache.size(1) == page_size, "ckv_cache page_size mismatch");

    // Create Outputs
    at::Tensor output = at::zeros({num_tokens, num_qo_heads, head_dim_ckv}, 
        at::TensorOptions().dtype(at::kBFloat16).device(at::kCUDA));
    at::Tensor lse = at::full({num_tokens, num_qo_heads}, -INFINITY, 
        at::TensorOptions().dtype(at::kFloat).device(at::kCUDA));

    // Launch Kernel
    launch_sparse_attention_kernel(
        q_nope.data_ptr(),
        q_pe.data_ptr(),
        ckv_cache.data_ptr(),
        kpe_cache.data_ptr(),
        sparse_indices.data_ptr<int>(),
        output.data_ptr(),
        lse.data_ptr<float>(),
        sm_scale,
        num_tokens
    );

    return {output, lse};
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "DSA Sparse Attention Kernel Execution");
}
